"""
MKT Context Commentary — 1 Samuel chapters 17–18
Run: python3 scripts/zc-context-1samuel-17-18.py

Source data used:
- data/interlinear/1samuel.json
- data/translation/draft/mediating/1samuel.json (MKT text)

Key context decisions:
- Ch17 is the most culturally layered chapter in 1 Samuel: ANE champion-combat (monomachy)
  conventions, Philistine military equipment, the giant-warrior (Rephaim) tradition, sling
  technology, honor-shame of defiance speech, and the "38 Greek text" textual problem
- The LXX (OG) lacks vv12-31, 41, 48b, 50, 55-58; these verses are widely considered a MT
  expansion. The MT version is the received canonical text; this commentary treats it as given
  but notes the LXX situation where relevant
- Ch18: ʾāhab (love) in political covenant contexts; Jonathan's robe-exchange as loyalty transfer;
  the women's battle-hymn as honor redistribution; bride-price manipulation; "the LORD was with him"
  as the theological refrain
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

SAMUEL1 = {
  "17": {
    "1": '<p>Socoh and Azekah are in the Shephelah (foothills) west of Bethlehem — the disputed zone where Judahite highlands meet the Philistine coastal plain. The name Ephes-dammim ("boundary of blood") signals this as a contested border. The Philistines routinely used this terrain to probe the highlands; the Elah Valley was a natural corridor into Judah. The two armies occupying opposite ridges with a valley between them is the standard ancient Near Eastern prelude to negotiated or champion combat rather than general engagement.</p>',
    "2": '<p>The Valley of Elah (ʿēmeq hāʾēlāh, "valley of the terebinth") — a seasonal wadi running east-west through the Shephelah. Saul\'s encampment on the north ridge facing the Philistines on the south ridge created the textbook standoff situation. Drawing up "battle lines" (<em>mā\'arākāh</em>) does not necessarily imply imminent general battle; the formation itself was often designed to provoke or deter.</p>',
    "3": '<p>The geography of the standoff — identical hills on opposite sides, valley between — mirrors the ANE literary convention of "balanced forces." Neither side has the geographic advantage, which creates the conditions for champion combat as an honorable resolution. The standoff in ancient warfare was expensive (troops must be fed and maintained) and unresolved stalemate was itself a form of defeat for the challenging side.</p>',
    "4": '<p><strong>Champion combat (monomachy)</strong> was a recognized military convention in the ancient Near East to settle disputes without general casualties. An Egyptian text describes Sinuhe\'s single combat; Homeric epic uses the same convention (Achilles, Paris). Goliath of Gath — Gath was one of the five Philistine city-states, historically associated with a giant-warrior tradition. The term <em>ʾîš habbênayyim</em> ("man of the between-space" = champion) is a technical term for the dueling combatant who stands in the open space between the two armies.</p>',
    "5": '<p>Goliath\'s armor is described with military precision: a bronze helmet (<em>kôḇaʿ nəḥōšet</em>), scale armor (<em>širyôn qaśqaśśîm</em>) weighing 5,000 bronze shekels (~125 lbs / 57 kg). Scale armor — small bronze plates attached to a leather backing — was standard elite Aegean and ANE equipment by the late Bronze Age. Its weight indicates Goliath was a heavily armed infantry champion, not a mobile skirmisher.</p>',
    "6": '<p>Bronze greaves (<em>miṣḥat nəḥōšet</em>) protecting the shins were characteristic of Aegean (Mycenaean/Sea Peoples) military equipment, notably absent from standard Canaanite or Egyptian warrior gear. The javelin (<em>kîdôn</em>) slung between the shoulders was a throwing weapon carried as a secondary arm. Goliath\'s armor kit marks him as a fighting-man of the Aegean military tradition that the Philistines brought with them from the west.</p>',
    "7": '<p>The spear shaft "as thick as a weaver\'s beam" (<em>kəmnôr ʾōrəḡîm</em>) is a formulaic description of extreme size also applied to other giant warriors (2 Sam 21:19; 1 Chr 20:5). The iron spearhead weighing 600 shekels (~15 lbs / 7 kg) reflects the Iron Age transition: iron weapons were superior to bronze and the Philistines controlled early iron technology in Canaan (cf. 13:19-22). The shield-bearer walking before him was a standard practice for heavily armed warriors; the bearer carried the large body-shield while the warrior used weapons.</p>',
    "8": '<p>Goliath\'s challenge speech follows the rhetoric of the ANE defiance call (<em>ḥērep</em>, reproach/taunt). The speech structure — identity declaration, challenge framing, stakes announcement — mirrors Mesopotamian and Egyptian military boast-texts. The question "are you not servants of Saul?" employs the honor-shame vocabulary of clientage: Israel is defined as the subjects of a human king, not as the people of a God. This framing challenges not just military capacity but the entire covenantal identity of Israel.</p>',
    "9": '<p>The conditional of champion combat: if the Israelite champion wins, Philistines serve Israel; if Goliath wins, Israel serves Philistia. This is the standard formula of binding arbitration through single combat. The loser\'s entire army accepts the political consequence — service/subjugation — without a general engagement. The system worked when both sides honored the outcome; in practice, the losing side often fled rather than surrendered (v51).</p>',
    "10": '<p><em>ḥārēp</em> (to reproach/taunt) — Goliath "defies" (<em>yəḥārēp</em>) the armies of Israel. The verb <em>ḥārap</em> (H2778) carries the social meaning of inflicting public shame — an act requiring a response to preserve honor. In an honor-shame culture, failure to respond to a public challenge was itself a damaging social statement. The forty-day repetition (v16) compounds the shame accumulation: Israel\'s silence is a forty-day statement of defeat without battle.</p>',
    "11": '<p>The mass response — dismay and terror — reflects the honor-shame calculation: the entire army recognized that Goliath\'s challenge demanded a champion, and none volunteered. Saul, the king who stood "head and shoulders above" all Israel (9:2) and was chosen partly for his physical stature, should have been the obvious respondent. His silence is the most shameful silence of all — the king who cannot or will not defend the honor of the army he leads.</p>',
    "12": '<p>The parenthetical introduction of David\'s family background — identifying him as an Ephrathite (a clan designation within Bethlehem, cf. Mic 5:2) and Jesse\'s youngest of eight sons — is one of the passages absent from the LXX\'s shorter text. The MT\'s extended introduction creates the impression that David is newly introduced to the narrative, though he has already served at Saul\'s court (ch16). Scholars debate whether the MT has conflated two originally independent David-traditions; the canonical text holds them together.</p>',
    "13": '<p>The three eldest sons are at war with Saul — their names (Eliab, Abinadab, Shammah) match those passed over in the anointing scene of ch16. Their presence in Saul\'s army rather than being returned home places them under Saul\'s command and thus in the position of shame — the brothers of the chosen one are serving the rejected king who does not know the chosen one has replaced him.</p>',
    "14": '<p>David as "the youngest" (<em>haqqāṭān</em>) — the birth-order reversal is a recurring biblical pattern (Jacob over Esau, Joseph over his brothers, Gideon the least in his clan). In ancient Near Eastern primogeniture culture, the youngest son\'s elevation over his elders requires divine intervention to be legitimate. The narrative consistently marks David\'s lowly position as the precondition for his exaltation.</p>',
    "15": '<p>David\'s commuting — between Saul\'s court and tending sheep at Bethlehem — is presented without explanation. In the honor-shame economy of the ancient world, a court attendant who also tended sheep would be seen as low status; David\'s shepherd occupation is the exact opposite of the warrior prestige Saul\'s court required. It also explains why he was not with the army — he was not yet a full-time military man.</p>',
    "16": '<p>Forty days — a biblical convention for a complete, full period (Moses on Sinai, forty years in the wilderness, Elijah\'s journey, Jesus in the wilderness). The forty-day duration of Goliath\'s challenge signals a crisis that has reached its maximum — it cannot continue without resolution. Each morning-and-evening (<em>babbōqer ûḇāʿereḇ</em>) appearance coincides with the two daily prayer times; Goliath\'s taunting occupies the same temporal slots as covenant worship.</p>',
    "17": '<p>Jesse\'s provisions — an ephah of roasted grain (<em>qālî</em>, parched grain — portable, light food for soldiers) and ten loaves — are the standard logistics of ancient military supply. Soldiers in ancient armies were often provisioned by family, especially in extended standoffs. Jesse\'s instruction to "check on your brothers" reflects the family-honor obligation: a father\'s representative monitoring the welfare of sons at war.</p>',
    "18": '<p>Ten portions of cheese (<em>ḥărîṣê he ḥālāḇ</em> — slices/curds of milk) sent to the unit commander is a gift of honor — the kind of tribute that maintained favorable relationships with those who had authority over one\'s kin. The instruction to "bring back some token from them" (literally "take their pledge" or "their shalom") was a practical check — confirming the brothers were alive and in good standing.</p>',
    "19": '<p>The narrator parenthetically confirms the geography: Saul and Jesse\'s sons are in the Elah Valley. The detail is necessary for the reader unfamiliar with the campaign — it places David\'s mission within the active combat zone, not a rear echelon.</p>',
    "20": '<p>"Rising early" (<em>wayyaškem babbōqer</em>) signals diligence and faithfulness — a virtue-marker in biblical narrative (cf. Abraham in Gen 22:3). David leaves the sheep with a keeper (<em>šōmēr</em>) — a responsible act that foreshadows his care for people entrusted to him. His arrival at the camp coincides with the battle formation shout — the dramatic timing places him in the middle of military action.</p>',
    "21": '<p>The battle formation — army facing army (<em>māʿărāḵāh liqrāʾt māʿărāḵāh</em>) — is the formal drawn-up battle line. Ancient armies did not simply rush at each other; the alignment itself was a statement of readiness and honor. The standoff between aligned formations could last hours while commanders assessed options.</p>',
    "22": '<p>David leaves his supplies with a logistics keeper — the same practical competence as v20. His running to the battle line and greeting his brothers before any action reflects the honor obligation of family solidarity. He is there as a family representative before he becomes a military agent.</p>',
    "23": '<p>The Philistine champion stepped out "from the ranks" (<em>miggedərôt</em>) — the formation lines. David hears the challenge directly for the first time; his response distinguishes him from every other Israelite. The repetition of "the champion of Gath" (<em>ʾîš habbênayyim</em>) recalls the forty-day context — David is hearing something that has already paralyzed the entire army.</p>',
    "24": '<p>The mass flight before Goliath — "all the men of Israel saw Goliath and fled before him in great fear" — is a public honor-shame catastrophe. Flight from a champion\'s approach is the ultimate acknowledgment of inability to respond. In the ancient world, this kind of visible retreat was deeply shaming for the entire community, not just individual soldiers.</p>',
    "25": '<p>The reward structure announced by the men — great wealth, royal daughter in marriage, tax exemption for father\'s house — is the standard ANE incentive package for heroic military service. Marriage to a king\'s daughter elevated a man into the royal kinship network; tax exemption (<em>ḥopšî</em>) removed the household from tributary obligation. These were not ad hoc bribes but recognized forms of patron-client honor distribution for exceptional service.</p>',
    "26": '<p>David\'s immediate framing of the challenge in theological terms — "who is this uncircumcised Philistine that he should defy (<em>ḥārap</em>) the armies of the living God?" — reflects the covenant perspective on circumcision as the marker of covenant inclusion. The Philistines\' uncircumcision was both a literal ethnic-religious fact and a status marker: they stood outside the covenant community and therefore had no right to challenge YHWH\'s people. The phrase "living God" (<em>ʾĕlōhîm ḥayyîm</em>) is striking — it defines YHWH\'s capacity to act, in contrast to the lifeless idols of Philistia.</p>',
    "27": '<p>The men confirm the reward package from v25. David is gathering intelligence while others have fled — his questions are tactically rational and honor-driven simultaneously. He hears both the military situation and the social contract governing its resolution.</p>',
    "28": '<p>Eliab\'s rebuke — "I know your pride and insolence" (<em>yādaʿtî ʾet zēdōnəḵā wəʾēt rōaʿ ləḇāḇəḵā</em>) — is a family-honor intervention. An older brother rebuking a younger for overstepping is the normal operation of primogeniture culture. Eliab characterizes David\'s presence as pretentious spectating rather than genuine service. The accusation of "pride" is ironic given that David has expressed only covenantal concern, not personal ambition.</p>',
    "29": '<p>David\'s reply — "Is there not a reason to ask?" (<em>hălōʾ dāḇār hûʾ</em>) — is a rhetorical deflection: he refuses to engage the honor-challenge from his brother and redirects the conversation. In honor-shame culture, refusing to be drawn into a family dispute in a public setting was the dignified response. He "turns away" and continues gathering information from other sources.</p>',
    "30": '<p>The repetition — David asks again and gets the same answer — serves to demonstrate that the reward package is real and publicly known, not something David misheard. The multiple witnesses create a legally valid basis for the claim he will later make on the reward (v25 terms fulfilled in ch18).</p>',
    "31": '<p>David\'s words "were reported to Saul" (<em>wayyuggad liśmûʾēl</em>) — information traveling upward through the command structure. The king, sitting paralyzed by the same fear as his army, hears of the only man willing to fight. Saul "sends for" David — the verb is the royal summons (<em>wayšlaḥ</em>), which David must obey.</p>',
    "32": '<p>"Let no one\'s heart fail because of him" (<em>ʾal yippōl lēḇ ʾādām ʿālāyw</em>) — David uses the idiom of heart-failing that had been used to describe Israel\'s demoralization. The phrase implies David has already identified the problem as a crisis of will rather than military capacity. His volunteering is not reckless bravado but a claim to be the missing element: a representative willing to stand in the champion\'s role.</p>',
    "33": '<p>Saul\'s objection is practical and culturally correct: David is a <em>naʿar</em> (youth/young man), and Goliath has been a <em>ʾîš milḥāmāh</em> (warrior) from his youth. In ancient military culture, fighting experience was the primary qualification for champion combat. Size, strength, and proven record were the credentials; a shepherd youth had none of these on the conventional scale.</p>',
    "34": '<p>David\'s argument from shepherd experience — lion and bear — is not a boast of raw courage but a theological argument: YHWH delivered him from those threats, and will therefore deliver him from this one. Shepherd-combat with predators was a real danger in ancient Judea; lions (now extinct in the region) and bears were documented threats to flocks. The shepherd\'s defense of his flock was both economically necessary and legally required — a shepherd who lost animals to predators was responsible.</p>',
    "35": '<p>The specific technique — pursuing, striking, recovering the lamb from the mouth, then seizing the predator by the beard — is the detailed account of a shepherd who has actually done this. "Beard" (<em>zaqqān</em>) suggests David fought large cats or bears at close range. In ancient Judean highland terrain, the sling was also a shepherd\'s primary defensive tool against predators at distance.</p>',
    "36": '<p>David draws the explicit theological parallel: lion, bear, and "this uncircumcised Philistine" are in the same category — threats to YHWH\'s flock (Israel). The term "uncircumcised" (<em>ʾārēl</em>) marks Goliath as outside the covenant community, which therefore makes his defiance of Israel a defiance of YHWH himself. David\'s framing transforms a military challenge into a theological one.</p>',
    "37": '<p>"YHWH who rescued me from the claws of the lion and the bear will rescue me from the hand of this Philistine" — David\'s confidence is explicitly grounded in YHWH\'s prior faithfulness, not in personal strength. This is the pattern of biblical warfare theology (cf. Ps 20; 33:16-17): the God who delivered in the past is the basis for confidence in the present. Saul\'s blessing — "may YHWH be with you" — echoes the theological credential that was already noted in 16:18: "YHWH is with him."</p>',
    "38": '<p>Saul clothes David in his own armor — the king\'s equipment, including the royal helmet and coat of mail. The gesture is significant: Saul is attempting to transfer his military identity to David through material investiture. In ancient cultures, wearing a king\'s armor was both a practical provision and a symbolic act of royal sponsorship. The irony is that Saul\'s armor — which should represent the ideal Israelite warrior — does not fit the one YHWH has chosen.</p>',
    "39": '<p>David removes the armor: "I cannot move in these — I have no experience with them" (<em>lōʾ ûḵaltî lalleḵet bāʾēlleh</em>). The incompatibility is physical (the armor is sized for the tallest man in Israel) and symbolic (David\'s relationship with YHWH operates through different means than conventional military equipment). The removal of Saul\'s armor is also a narrative signal: the divine mandate will not be executed through the royal establishment\'s conventional instruments.</p>',
    "40": '<p>The shepherd\'s kit: staff, five smooth stones, shepherd\'s bag (<em>yalqûṭ</em>), and sling. The sling (<em>qelaʿ</em>) was a serious weapon of war — Judges 20:16 records 700 left-handed Benjaminite slingers who "could sling a stone at a hair and not miss." Ancient armies fielded slingers as effective range weapons; the Philistines\' very lack of concern about David\'s sling demonstrates their cultural unfamiliarity with its capability. Five stones may reflect that Goliath had four brothers (2 Sam 21:18-22) — but the narrative does not make this explicit.</p>',
    "41": '<p>Goliath advancing with his shield-bearer — the formal duel protocol, with the champion properly attended. The shield-bearer\'s role was to protect the heavily armed main fighter until close combat began. The disparity between this full military escort and David\'s shepherd equipment is the visual contrast the narrative exploits.</p>',
    "42": '<p>Goliath "looked David over" (<em>wayyabbeṭ</em>) and "despised him" (<em>wayyibzēhû</em>) — the honor-shame vocabulary of contempt. Goliath sees youth, ruddiness (ʾadmōnî — the same feature noted in David\'s anointing scene, 16:12), and handsomeness: all the marks of a non-warrior. The contempt is the appropriate response from the honor-framework Goliath operates in; he cannot read the theological reality.</p>',
    "43": '<p>"Am I a dog (<em>keleḇ</em>) that you come at me with a stick?" — Goliath uses the dog insult, the strongest ANE expression of contempt (cf. 24:14, "a dead dog"). Being challenged by a stick-carrying youth is equivalent to being treated as the lowest of animals. "The Philistine cursed David by his gods" (<em>wayyəqalel</em>) — formal curse-imprecation invoking divine power against David. The contrast with David\'s invocation of YHWH (v45) is the theological center of the exchange.</p>',
    "44": '<p>Goliath\'s counter-threat — birds and beasts consuming David\'s flesh — is the standard ANE "threat of non-burial." Exposure to carrion birds was the ultimate dishonorable death in ancient cultures: it denied the dead both burial and the afterlife associated with proper interment. Goliath\'s threat is designed to invoke maximum dread. David will turn this exact threat back on Goliath (v46).</p>',
    "45": '<p>"I come against you in the name (<em>šēm</em>) of YHWH of Hosts" — the divine-name invocation as warrior credential. In ancient Near Eastern warfare, to fight "in the name of" a god was to claim that god\'s authority and power as backing. YHWH of Hosts (<em>YHWH ṣəḇāʾôt</em>) is specifically the divine-warrior title — the God of cosmic and earthly armies. David\'s equipment is the divine Name; Goliath\'s is metal and iron.</p>',
    "46": '<p>David\'s speech reverses Goliath\'s threat point by point: "I will strike you down, cut off your head, give your corpse and the corpses of the Philistine camp to the birds of the sky and the beasts of the earth." The same fate Goliath promised David is pronounced on Goliath and his entire army. The purpose clause — "so that all the earth may know that there is a God in Israel" — frames the battle as a witness event for the watching nations, not merely a military engagement.</p>',
    "47": '<p>"The battle belongs to YHWH" (<em>laYHWH hamməlḥāmāh</em>) — the theology of holy war inherited from the Exodus and Conquest traditions. YHWH is the warrior who fights for Israel; human weapons are instruments, not causes, of victory. This principle governs the DtrH\'s evaluation of kings: those who trust weapons over YHWH fail (cf. Deut 17:16; Ps 20:7). David articulates the theological framework before the battle — this is not post-hoc interpretation.</p>',
    "48": '<p>David "ran quickly" (<em>waymaher wayyāruṣ</em>) toward the Philistine — the aggressive advance rather than waiting for Goliath to close the distance. The sling required distance and motion to generate velocity; David\'s running toward Goliath while his hand reached for a stone (v49) was the optimal sling-attack tactic: close enough for accuracy, far enough for momentum. The initiative shift — the defender becomes the attacker — is both tactically and symbolically significant.</p>',
    "49": '<p>The stone sinks into Goliath\'s forehead (<em>miṣḥô</em>) — the exposed face area between the helmet rim and the cheek guard. Ancient bronze helmets protected the skull but left the face exposed; a sling-stone striking with sufficient force in this gap would be lethal. The detail is militarily accurate: Goliath\'s armor protected everything except the face, and the sling-stone found the one unprotected point.</p>',
    "50": '<p>The summary note — "David had no sword in his hand" — emphasizes the theological point of v47: YHWH\'s victory through unexpected means. The stone and sling are shepherd\'s tools, not warrior\'s weapons; the absence of a sword from David\'s hand at the moment of kill is the narrative\'s visual confirmation that YHWH, not human weaponry, accomplished the defeat.</p>',
    "51": '<p>David uses Goliath\'s own sword to finish him and take his head — a reversal that completed the honorable termination of champion combat: the winner possessing the loser\'s weapon. The Philistines\' flight when they see their champion dead ends the "champion combat resolves everything" protocol: they chose not to honor the binding terms of v9 and fled instead. Israel\'s pursuit signals the protocol breakdown; this becomes a general engagement.</p>',
    "52": '<p>The pursuit extends to Gath and Ekron — two of the five Philistine city-states. The place-name Shaaraim (meaning "two gates") marked the entrance to the Shephelah. The breadth of the pursuit underscores the scale of the victory; Israel pursued not just from the Elah Valley but into Philistine territory itself.</p>',
    "53": '<p>The plundering of the Philistine camp after the pursuit was standard ancient military practice — the army that fled abandoned its logistical base. The camp\'s goods became the property of the victors, and the plunder was distributed through the chain of command. This is the "spoil" that will be distributed in later chapters.</p>',
    "54": '<p>David brings Goliath\'s head to Jerusalem — though Jerusalem was not yet an Israelite city (it falls to David in 2 Sam 5). The verse is either anachronistic (written after Jerusalem became David\'s capital) or refers to a pre-Davidic Israelite presence there. David places Goliath\'s armor in "his own tent" — asserting personal ownership of the trophy weapon, which will later be kept at Nob (21:9).</p>',
    "55": '<p>Saul\'s question — "Whose son is this young man?" — creates the famous textual problem: Saul has already welcomed David into his court (ch16). The LXX does not have this scene. Most scholars read the MT\'s "two stories" as originally independent traditions subsequently woven together. Within the MT narrative, one reading is that Saul is asking about family lineage for the purpose of fulfilling the marriage-reward of v25 (the reward required knowing the father\'s house to exempt it from taxes). Another reading is narrative discontinuity in a composite text.</p>',
    "56": '<p>"Find out whose son this young man is" — the king issuing a command to gather lineage information before making a marriage covenant. In ancient Israelite law and practice, marriage contracts were arranged between families, not merely individuals; Saul needed Jesse\'s identity to formalize the reward terms of v25.</p>',
    "57": '<p>Abner brings David before Saul "with the Philistine\'s head still in his hand" — the trophy that identifies the victor. The formal presentation to the king, head in hand, is the ancient protocol for reporting a military victory and claiming its associated honor.</p>',
    "58": '<p>David\'s self-identification — "I am the son of your servant Jesse the Bethlehemite" — uses the language of clientage (<em>ʿabdəḵā</em>, "your servant" applied to his father). The construction acknowledges David as belonging to the king\'s service network through his father. This closes ch17 by placing David within the social structure from which his story will unfold.</p>'
  },
  "18": {
    "1": '<p>"The soul of Jonathan was bound to the soul of David" (<em>nišmat yəhônātān niqšərāh bənepesh dāwid</em>) — the covenant-binding vocabulary. <em>Qāšar</em> (to bind/tie) was the term for formal alliance; the same root describes conspiracies and political covenants elsewhere in Samuel. Jonathan\'s love "as his own soul" (<em>kənaphšô</em>) is not merely emotional affection but the language of political alliance — the same terminology appears in Deuteronomy 13:6 for the closest kinship bonds and in covenant contexts throughout the ancient Near East. This is a covenantal loyalty, sealed with formal acts in vv3-4.</p>',
    "2": '<p>Saul "kept David with him from that day on" — the king retaining a military asset at court. The phrase "would not let him return to his father\'s house" reflects the ancient Near Eastern practice of the king claiming the service of exceptional military talent. David transitions from occasional courtier (16:21-22) to permanent royal attendant.</p>',
    "3": '<p><strong>Jonathan\'s covenant</strong> (<em>kārat bərît</em>) — "cut a covenant," the standard legal formula. The verb <em>kārat</em> (to cut) refers to the covenant ratification ritual in which animals were cut (cf. Gen 15). Jonathan\'s covenant with David is made in the context of military victory — the most natural setting for political alliance. The covenant is grounded in <em>ʾāhab</em> (love), which in political contexts means loyalty-commitment, not primarily emotional feeling.</p>',
    "4": '<p>Jonathan\'s robe-exchange is the most symbolically loaded act in the chapter. Giving one\'s robe (<em>məʿîl</em>) in the ancient Near East was an act of personal investiture — transferring identity, status, and authority. The Hittite treaty tradition records robe-giving as a symbol of succession and authority transfer. Jonathan, the crown prince who would normally succeed Saul, gives his robe to David — an act that the narrative retrospectively reads as Jonathan\'s implicit acknowledgment of the divine election of David over himself. The sword, bow, and belt complete the transfer: Jonathan gives David a warrior\'s full equipment, the accoutrements of the heir-apparent.</p>',
    "5": '<p>"David had success in everything he did" (<em>maśkîl bəkol ʾăšer yišlaḥehû šāʾûl</em>) — the key word is <em>śākal</em> (Hiphil, to act wisely/successfully). This is the wisdom-success vocabulary: David\'s effectiveness is not raw strength but God-given prudence. "All the people and Saul\'s servants accepted him" — the concentric circles of acceptance (army, courtiers, king) mark David\'s consolidation as a figure of public legitimacy.</p>',
    "6": '<p>The victory procession with women coming out to greet returning warriors was a regular Israelite institution (cf. Judg 11:34; Exod 15:20). Women played the tambourines (<em>tuppîm</em>) and performed antiphonal songs — a recognized cultural form of honoring military heroes. The greeting of returning warriors by women was public honor-distribution; it was also how the community processed the transition from military emergency to peacetime.</p>',
    "7": '<p>The battle-hymn — "Saul has struck down his thousands, David his ten thousands" — is an antiphonal song in the standard Hebrew numerical poetic form (X / X+1 for rhetorical escalation). The form itself does not necessarily mean David killed ten times more than Saul; it is a literary device of intensification. But in the honor-shame economy of the royal court, the assignment of the higher number to the subordinate was a public honor-challenge to the king. Saul correctly reads its social meaning.</p>',
    "8": '<p>Saul\'s reading — "they have given David ten thousands and me only thousands — what more can he have but the kingdom?" — is politically astute. In ancient patronage systems, public honor (honor-claims through song, monument, recognition) were political currency. A king whose subjects publicly assigned greater honor to a subordinate was witnessing a transfer of social capital that could precede political transfer. Saul\'s paranoia is not irrational; it is the correct reading of honor-redistribution in his cultural context.</p>',
    "9": '<p>"From that day Saul watched David with suspicion" (<em>wayhî šāʾûl ʿôyēn ʾet dāwid</em>) — <em>ʿāyan</em> (H5770, to eye/watch with envy/suspicion) is a surveillance verb. The king\'s protective gaze over his court has become a hostile gaze of potential threat-monitoring. The transition from patron to rival is now established.</p>',
    "10": '<p>The "evil spirit from God" coming upon Saul — the third reference to this affliction (16:14-16, 16:23, now 18:10). <em>Wayyitnabbēʾ</em> — "he went into a frenzy" — the Hithpael of <em>nāḇāʾ</em> (to prophesy) denotes an ecstatic state. The verb is used for both genuine prophecy and frenzied behavior elsewhere (10:10-11; Num 11:25-27); here it describes uncontrolled agitated behavior. The temporal note "the next day" immediately after the song episode connects Saul\'s mental deterioration to the honor-challenge of the battle-hymn.</p>',
    "11": '<p>The spear-throwing — "I will pin David to the wall" (<em>akkem baddāwid ûḇaqqîr</em>, "I will strike David through to the wall") — is the action of a man who has abandoned strategic cunning for direct violence. The spear was Saul\'s royal symbol (22:6: "Saul was sitting under the tamarisk tree with his spear in hand"). Hurling it at David is an act of royal violence against a covenant member of the court. David "eluded him twice" — the twice-repeated failure emphasizes both David\'s deliverance and Saul\'s increasing desperation.</p>',
    "12": '<p>"Saul was afraid of David because YHWH was with him (<em>hāyāh YHWH ʿimmô</em>) but had departed from Saul" — the theological explanation for Saul\'s fear. The formula "YHWH was with X" is the DtrH\'s standard success-attribution (used of Joseph in Gen 39:2, 23; Joshua 6:27; Samuel 3:19). The explicit contrast — with David / departed from Saul — is the two-sentence summary of the entire transfer of divine favor that ch16 narrated.</p>',
    "13": '<p>Saul\'s removal of David from "personal service" (<em>mēʿimmô</em>, from beside him) and appointment as commander of a thousand was a demotion-promotion: it removed a threat from the court inner circle while giving David a military command that could expose him to danger. The calculation — "let the Philistines kill him" (explicit in v17, 25) — is the logic of using military risk to eliminate a rival without direct royal action. The honor-shame system protected Saul from being seen as personally targeting a covenant member.</p>',
    "14": '<p>"David had success in all his undertakings (<em>maśkîl bəkol dərāḵāyw</em>) for YHWH was with him" — the refrain of divine accompaniment is repeated. The Hiphil participle <em>maśkîl</em> (acting wisely/prospering) became the technical term for wisdom-guided success. Success in battle was read in the ancient world as divine approval; David\'s unbroken military success was an objective indicator, not just a theological claim.</p>',
    "15": '<p>Saul\'s fear of David escalates precisely because of David\'s consistent success. In honor-shame culture, consistent public success accumulated social capital that could not be easily reversed. Each victory added to David\'s honor-standing; Saul had no way to cap the accumulation except by removing David from scenarios where he could succeed — which paradoxically gave David more authority.</p>',
    "16": '<p>"All Israel and Judah loved David" — <em>ʾāhab</em> again, now applied to the entire nation. The love-loyalty of the people for David contrasts with Saul\'s fear of David. In political terms, the king who cannot generate popular affection while his subordinate does is already losing the loyalty contest. The mention of both "Israel and Judah" is unusual — it anticipates the north-south division that will follow Saul\'s death.</p>',
    "17": '<p>Saul\'s offer of Merab — "I will give her to you in marriage. Only be courageous and fight YHWH\'s battles" — uses marriage alliance as a mechanism for dangerous military deployment. The phrase "fight YHWH\'s battles" (<em>leḥem milḥamôt YHWH</em>) is ironic: Saul frames dangerous missions in theological language to maintain plausible deniability. The narrator reveals the actual intent: "let the Philistines do it" — outsourcing David\'s elimination to the enemy.</p>',
    "18": '<p>David\'s response — "Who am I? And what is my life, or my father\'s family?" — is the protocol of honorable self-deprecation before a king\'s offer. Accepting a royal offer too quickly was socially gauche; the proper response was to minimize one\'s own worthiness. David\'s reference to being "a poor man of no importance" (<em>ʾîš rāš ûniqāleh</em>) is both social courtesy and a genuine statement of his status relative to the royal house.</p>',
    "19": '<p>Merab being given to Adriel the Meholathite instead of David — without explanation — leaves David in a socially awkward position: the king had publicly offered and then withdrawn the offer. In honor-shame culture, this was a public slight. The narrative does not moralize; it simply records the outcome and the implicit slight, which adds to the accumulating list of injuries Saul inflicts on David without direct violence.</p>',
    "20": '<p>Michal\'s love for David is the second royal love-bond of the chapter (after Jonathan\'s in v1). The narrator notes that "when Saul was told, the news pleased him" — a reversal of Merab\'s situation. Saul sees Michal\'s love as an opportunity to use marriage as a trap (<em>môqēš</em>) rather than a gift. The word <em>môqēš</em> (snare, v21) is the term for a trap used in hunting — Saul is treating his own daughter\'s love as a weapon against David.</p>',
    "21": '<p>Saul\'s strategy: "I will give her to him; she will be a trap for him." The snare logic: a royal daughter requires protection, generating military obligations that expose David to danger. Alternatively, a royal marriage could generate political claims that Saul could use as a pretext against David. The phrase "through one of the two" (<em>bišetayim</em>) — "you shall be my son-in-law today through one of the two daughters" — suggests Saul had reconsidered after the Merab episode and now offers Michal as the alternative path.</p>',
    "22": '<p>Saul\'s use of intermediaries — instructing his servants to "speak to David privately" — is the protocol of indirect royal communication for sensitive negotiations. The court operated through intermediaries to maintain deniability and proper social distance. The servants\' role as go-betweens also created a layer of witnesses for whatever transaction followed.</p>',
    "23": '<p>David\'s second self-deprecation — "does it seem a small thing to become the king\'s son-in-law? I am a poor man of no importance" — reuses the language of v18. The repetition is deliberate: David consistently declines to grab at royal status, which is itself an honorable quality. The "poor man" (<em>ʾîš rāš</em>) claim is probably not literally true (David commanded hundreds of men) but is the correct social register for a private citizen addressing a king\'s marriage offer.</p>',
    "24": '<p>The servants report David\'s reply back to Saul — the proper protocol: the intermediary carries the message in both directions and reports the outcome to the initiating party. Saul\'s scheme requires accurate intelligence about David\'s response to calibrate the next step.</p>',
    "25": '<p>The bride-price demand — one hundred Philistine foreskins instead of wealth — is a lethal cleverness. The standard <em>mōhar</em> (bride-price) was paid in goods or silver; Saul substitutes a military task that requires David to engage Philistines at close range and defeat them one-on-one. The foreskin trophy was a recognized form of counting enemy dead (cf. 2 Sam 3:14 where David refers to this event; also Judg 8:24-26, Gideon\'s gold ear-rings from enemies). The requirement verifies the kills are Philistine (circumcision-status determined in the field) and maximizes the danger to David.</p>',
    "26": '<p>"It seemed good to David to become the king\'s son-in-law" — David accepts the terms. The phrase "the time allotted had not yet passed" implies Saul had set a deadline — another element of control. David\'s acceptance is not naive; he apparently calculated that the mission was achievable and worth the risk for the political benefit of royal kinship.</p>',
    "27": '<p>David brings two hundred foreskins — double the required hundred. The doubling is both a demonstration of military capacity and a social statement: he overfulfills the requirement rather than barely meeting it. In patron-client culture, exceeding expectations was the highest form of service. The presentation "in full count to the king" is the formal delivery of the bride-price; Saul gives Michal to David. The marriage is completed through military service rather than economic exchange.</p>',
    "28": '<p>"Saul recognized that YHWH was with David" — the recognition formula: <em>wayyarʾ</em> (saw/recognized). The accumulation of evidence is finally acknowledged by Saul himself. That Michal loved David is added as a second piece of evidence — the king\'s own daughter\'s love for the chosen man is another confirmation of what Saul had tried to exploit as a trap.</p>',
    "29": '<p>"Saul became even more afraid" (<em>wayyōsep šāʾûl lîrāʾ</em>, literally "Saul added to fearing") — the fear compounds rather than resolving. "Saul was David\'s enemy from then on" (<em>ʿôyēḇ</em>) — the first use of the formal "enemy" vocabulary for the king-subject relationship. The transition from suspicious patron (v9) to explicit enemy is now complete. The honor-accumulation David had achieved — royal marriage, military success, popular love — has crossed the threshold Saul can no longer rationalize as non-threatening.</p>',
    "30": '<p>"Whenever the Philistine commanders went out on raids, David performed more successfully than all of Saul\'s other officers" — the closing summary maintains the theological refrain of consistent success. <em>Wayyîqar šəmô məʾōd</em> — "his reputation grew greatly" (literally "his name was precious/valued"). The Hebrew <em>yāqar</em> (precious/weighty) describes honor-accumulation in the public social register — David\'s name had become a commodity of recognized worth. The chapter closes as it opened: David winning honor at every turn, Saul\'s position relative to him deteriorating with each success.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', '1samuel')
    merge_comm(existing, SAMUEL1)
    save_comm('mkt-context', '1samuel', existing)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / '1samuel.json'))
    all_ok = True
    for ch in [17, 18]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(existing.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(existing.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
